import{_ as i}from"./plugin-vue_export-helper.21dcd24c.js";import{r as h,o as t,c as d,a,b as o,F as s,f as r,d as e}from"./app.5f3c891e.js";const c={},p=r('<h1 id="solid\u539F\u5219" tabindex="-1"><a class="header-anchor" href="#solid\u539F\u5219" aria-hidden="true">#</a> SOLID\u539F\u5219</h1><h2 id="solid\u539F\u5219-1" tabindex="-1"><a class="header-anchor" href="#solid\u539F\u5219-1" aria-hidden="true">#</a> SOLID\u539F\u5219</h2><p>\u8FD9\u4E94\u6761\u539F\u5219\u662F\u5728\u7F57\u4F2F\u7279\xB7\u9A6C\u4E01\u7684\u8457 \u4F5C\u300A\u654F\u6377\u8F6F\u4EF6\u5F00\u53D1\uFF1A\u539F\u5219\u3001\u6A21\u5F0F\u4E0E\u5B9E\u8DF5\u300B\u4E2D\u9996\u6B21\u63D0\u51FA\u7684\u3002</p><p>SOLID \u662F\u8BA9\u8F6F\u4EF6\u8BBE\u8BA1\u66F4\u6613\u4E8E\u7406\u89E3\u3001\u66F4\u52A0\u7075\u6D3B\u548C\u66F4\u6613\u4E8E\u7EF4\u62A4\u7684 \u4E94\u4E2A\u539F\u5219\u7684\u7B80\u79F0\u3002\u4E0E\u751F\u6D3B\u4E2D\u6240\u6709\u4E8B\u60C5\u4E00\u6837\uFF0C\u76F2\u76EE\u9075\u5B88\u8FD9\u4E9B\u539F\u5219\u53EF\u80FD\u4F1A\u5F0A\u5927\u4E8E\u5229\u3002\u5728\u7A0B\u5E8F\u67B6\u6784\u4E2D\u5E94\u7528\u8FD9\u4E9B\u539F\u5219\u53EF\u80FD\u4F1A\u4F7F\u5176\u53D8\u5F97\u8FC7\u4E8E\u590D\u6742\u3002\u6211\u5BF9\u4E8E\u662F\u5426\u771F\u7684\u6709\u80FD\u591F\u540C\u65F6\u5E94\u7528\u6240\u6709\u8FD9\u4E94\u6761\u539F\u5219\u7684\u6210\u529F\u8F6F\u4EF6\u4EA7\u54C1\u8868\u793A\u6000\u7591\u3002\u6709\u539F\u5219\u662F\u4EF6\u597D\u4E8B\uFF0C\u4F46\u662F\u4E5F\u8981\u65F6\u523B\u4ECE\u5B9E\u7528\u7684\u89D2\u5EA6\u6765 \u8003\u91CF\uFF0C\u4E0D\u8981\u628A\u8FD9\u91CC\u7684\u6BCF\u53E5\u8BDD\u5F53\u4F5C\u653E\u4E4B\u56DB\u6D77\u7686\u51C6\u7684\u6559\u6761\u3002</p><h3 id="\u5355\u4E00\u804C\u8D23\u539F\u5219" tabindex="-1"><a class="header-anchor" href="#\u5355\u4E00\u804C\u8D23\u539F\u5219" aria-hidden="true">#</a> \u5355\u4E00\u804C\u8D23\u539F\u5219</h3><p>\u5355\u4E00\u804C\u8D23\u539F\u5219\uFF08Single Responsibility Principle\uFF09\uFF1A\u4FEE\u6539\u4E00\u4E2A\u7C7B\u7684\u539F\u56E0\u53EA\u80FD\u6709\u4E00\u4E2A\u3002</p><p>\u8FD9\u4E2A\u539F\u5219\u4E0D\u4EC5\u4EC5\u9002\u7528\u4E8E\u7C7B\uFF0C\u5BF9\u4E8E\u63A5\u53E3\u548C\u65B9\u6CD5\u4E5F\u9002\u7528\uFF0C\u5373\u4E00\u4E2A\u63A5\u53E3/\u65B9\u6CD5\uFF0C\u53EA\u8D1F\u8D23\u4E00\u4EF6\u4E8B\uFF0C\u8FD9\u6837\u7684\u8BDD\uFF0C\u63A5\u53E3\u5C31\u4F1A\u53D8\u5F97\u7B80\u5355\uFF0C\u65B9\u6CD5\u4E2D\u7684\u4EE3\u7801\u4E5F\u4F1A\u66F4\u5C11\uFF0C\u6613\u8BFB\uFF0C\u4FBF\u4E8E\u7EF4\u62A4\u3002</p><p>\u4E8B\u5B9E\u4E0A\uFF0C\u7531\u4E8E\u4E00\u4E9B\u5176\u4ED6\u7684\u56E0\u7D20\u5F71\u54CD\uFF0C\u7C7B\u7684\u5355\u4E00\u804C\u8D23\u5728\u9879\u76EE\u4E2D\u662F\u5F88\u96BE\u4FDD\u8BC1\u7684\u3002\u901A\u5E38\uFF0C\u63A5\u53E3\u548C\u65B9\u6CD5\u7684\u5355\u4E00\u804C\u8D23\u66F4\u5BB9\u6613\u5B9E\u73B0\u3002</p><h3 id="\u5F00\u95ED\u539F\u5219" tabindex="-1"><a class="header-anchor" href="#\u5F00\u95ED\u539F\u5219" aria-hidden="true">#</a> \u5F00\u95ED\u539F\u5219</h3><p>\u5F00\u95ED\u539F\u5219\uFF08Open/closed Principle)\uFF1A\u5BF9\u4E8E\u6269\u5C55\uFF0C\u7C7B\u5E94\u8BE5\u662F\u201C\u5F00\u653E\u201D\u7684\uFF1B\u5BF9\u4E8E\u4FEE\u6539\uFF0C\u7C7B\u5219\u5E94\u662F\u201C\u5C01\u95ED\u201D\u7684\u3002</p><p>\u5982\u679C\u4F60\u53EF\u4EE5\u5BF9\u4E00\u4E2A\u7C7B\u8FDB\u884C\u6269\u5C55\uFF0C\u53EF\u4EE5\u521B\u5EFA\u5B83\u7684\u5B50\u7C7B\u5E76\u5BF9\u5176\u505A\u4EFB\u4F55\u4E8B\u60C5\uFF08\u5982\u65B0\u589E\u65B9\u6CD5\u6216\u6210\u5458\u53D8\u91CF\u3001\u91CD\u5199\u57FA\u7C7B\u884C\u4E3A\u7B49\uFF09\uFF0C\u90A3\u4E48\u5B83\u5C31\u662F<strong>\u5F00\u653E</strong>\u7684\u3002\u6709\u4E9B\u7F16\u7A0B\u8BED\u8A00\u5141\u8BB8\u4F60\u901A\u8FC7\u7279\u6B8A\u5173\u952E\u5B57\uFF08\u4F8B\u5982 final \uFF09\u6765\u9650\u5236\u5BF9\u4E8E\u7C7B\u7684\u8FDB\u4E00\u6B65\u6269\u5C55\uFF0C \u8FD9\u6837\u7C7B\u5C31\u4E0D\u518D\u662F\u201C\u5F00\u653E\u201D\u7684\u4E86\u3002\u5982\u679C\u67D0\u4E2A\u7C7B\u5DF2\u505A\u597D\u4E86\u5145\u5206\u7684\u51C6\u5907\u5E76\u53EF\u4F9B\u5176\u4ED6\u7C7B\u4F7F\u7528\u7684\u8BDD\uFF08\u5373\u5176\u63A5\u53E3\u5DF2\u660E\u786E\u5B9A\u4E49\u4E14\u4EE5\u540E\u4E0D\u4F1A\u4FEE\u6539\uFF09\uFF0C\u90A3\u4E48\u8BE5\u7C7B\u5C31\u662F<strong>\u5C01\u95ED</strong>\uFF08\u4F60\u53EF\u4EE5\u79F0\u4E4B\u4E3A<strong>\u5B8C\u6574</strong>\uFF09\u7684\u3002</p><p>\u4E5F\u5C31\u662F\u8BF4\uFF0C\u5982\u679C\u4E00\u4E2A\u7C7B\u5DF2\u7ECF\u5B8C\u6210\u5F00\u53D1\u3001\u6D4B\u8BD5\u548C\u5BA1\u6838\u5DE5\u4F5C\uFF0C\u800C\u4E14\u5C5E\u4E8E\u67D0\u4E2A\u6846\u67B6\u6216\u8005\u53EF\u88AB\u5176\u4ED6\u7C7B\u7684\u4EE3\u7801\u76F4\u63A5\u4F7F\u7528\u7684\u8BDD\uFF0C\u5BF9\u5176\u4EE3\u7801\u8FDB\u884C\u4FEE\u6539\u5C31\u662F\u6709\u98CE\u9669\u7684\u3002\u4F60\u53EF\u4EE5\u521B\u5EFA\u4E00\u4E2A\u5B50\u7C7B\u5E76\u91CD\u5199\u539F\u59CB\u7C7B\u7684\u90E8\u5206\u5185\u5BB9\u4EE5\u5B8C\u6210\u4E0D\u540C\u7684\u884C\u4E3A\uFF0C\u800C\u4E0D\u662F\u76F4\u63A5\u5BF9\u539F\u59CB\u7C7B\u7684\u4EE3\u7801\u8FDB\u884C\u4FEE\u6539\u3002\u8FD9\u6837\u4F60\u65E2\u53EF\u4EE5\u8FBE\u6210\u81EA\u5DF1\u7684\u76EE\u6807\uFF0C\u4F46\u540C\u65F6\u53C8\u65E0\u9700\u4FEE\u6539\u5DF2\u6709\u7684\u539F\u59CB\u7C7B\u5BA2\u6237\u7AEF\u3002</p><p>\u8FD9\u6761\u539F\u5219\u5E76\u4E0D\u80FD\u5E94\u7528\u4E8E\u6240\u6709\u5BF9\u7C7B\u8FDB\u884C\u7684\u4FEE\u6539\u4E2D\u3002\u5982\u679C\u4F60\u53D1\u73B0\u7C7B\u4E2D\u5B58\u5728\u7F3A\u9677\uFF0C\u76F4\u63A5\u5BF9\u5176\u8FDB\u884C\u4FEE\u590D\u5373\u53EF\uFF0C\u4E0D\u8981\u4E3A\u5B83\u521B\u5EFA\u5B50\u7C7B\u3002\u5B50\u7C7B\u4E0D\u5E94\u8BE5\u5BF9\u5176\u7236\u7C7B\u7684\u95EE\u9898\u8D1F\u8D23\u3002</p><h3 id="\u91CC\u6C0F\u66FF\u6362\u539F\u5219" tabindex="-1"><a class="header-anchor" href="#\u91CC\u6C0F\u66FF\u6362\u539F\u5219" aria-hidden="true">#</a> \u91CC\u6C0F\u66FF\u6362\u539F\u5219</h3>',14),l=e("("),_={href:"https://www.jianshu.com/p/dfcdcd5d9ece",target:"_blank",rel:"noopener noreferrer"},f=e("\u516D\u5927\u8BBE\u8BA1\u539F\u5219\u4E4B\u91CC\u6C0F\u66FF\u6362\u539F\u5219\uFF08LSP\uFF09 - \u7B80\u4E66 (jianshu.com)"),u=e(")"),x=r('<p>\u91CC\u6C0F\u66FF\u6362\u539F\u5219\uFF08Liskov Substitution Principle\uFF09\uFF1A\u5F53\u62D3\u5C55\u4E00\u4E2A\u7C7B\u65F6\uFF0C\u5E94\u8BE5\u8981\u80FD\u5728\u4E0D\u4FEE\u6539\u5BA2\u6237\u7AEF\u4EE3\u7801\u7684\u60C5\u51B5\u4E0B\u5C06\u5B50\u7C7B\u7684\u5BF9\u8C61\u4F5C\u4E3A\u7236\u7C7B\u5BF9\u8C61\u8FDB\u884C\u4F20\u9012\u3002</p><h4 id="_1-\u5B50\u7C7B\u5FC5\u987B\u5B9E\u73B0\u7236\u7C7B\u7684\u62BD\u8C61\u65B9\u6CD5-\u4F46\u4E0D\u5F97\u91CD\u5199-\u8986\u76D6-\u7236\u7C7B\u7684\u975E\u62BD\u8C61-\u5DF2\u5B9E\u73B0-\u65B9\u6CD5" tabindex="-1"><a class="header-anchor" href="#_1-\u5B50\u7C7B\u5FC5\u987B\u5B9E\u73B0\u7236\u7C7B\u7684\u62BD\u8C61\u65B9\u6CD5-\u4F46\u4E0D\u5F97\u91CD\u5199-\u8986\u76D6-\u7236\u7C7B\u7684\u975E\u62BD\u8C61-\u5DF2\u5B9E\u73B0-\u65B9\u6CD5" aria-hidden="true">#</a> 1. \u5B50\u7C7B\u5FC5\u987B\u5B9E\u73B0\u7236\u7C7B\u7684\u62BD\u8C61\u65B9\u6CD5\uFF0C\u4F46\u4E0D\u5F97\u91CD\u5199\uFF08\u8986\u76D6\uFF09\u7236\u7C7B\u7684\u975E\u62BD\u8C61\uFF08\u5DF2\u5B9E\u73B0\uFF09\u65B9\u6CD5</h4><p>\u6211\u4EEC\u53EF\u4EE5\u7ED9\u7236\u7C7B\u7684\u975E\u62BD\u8C61\uFF08\u5DF2\u5B9E\u73B0\uFF09\u65B9\u6CD5\u52A0final\u4FEE\u9970\uFF0C\u8FD9\u6837\u5C31\u5728\u8BED\u6CD5\u5C42\u9762\u63A7\u5236\u4E86\u7236\u7C7B\u975E\u62BD\u8C61\u65B9\u6CD5\u88AB\u5B50\u7C7B\u91CD\u5199\u800C\u8FDD\u53CD\u91CC\u6C0F\u66FF\u6362\u539F\u5219\u3002</p><p>\u6709\u65F6\u5019\u7236\u7C7B\u6709\u591A\u4E2A\u5B50\u7C7B(Son1\u3001Son2)\uFF0C\u4F46\u5728\u8FD9\u4E9B\u5B50\u7C7B\u4E2D\u6709\u4E00\u4E2A\u7279\u4F8B(Son2)\u3002\u8981\u60F3\u6EE1\u8DB3\u91CC\u6C0F\u66FF\u6362\u539F\u5219\uFF0C\u53C8\u60F3\u6EE1\u8DB3\u8FD9\u4E2A\u5B50\u7C7B\u7684\u529F\u80FD\u65F6\uFF0C\u6709\u7684\u4F19\u4F34\u53EF\u80FD\u4F1A\u4FEE\u6539\u7236\u7C7B(Father)\u7684\u65B9\u6CD5\u3002\u4F46\u662F\uFF0C\u4FEE\u6539\u4E86\u7236\u7C7B\u7684\u65B9\u6CD5\u53C8\u4F1A\u5BF9\u5176\u4ED6\u7684\u5B50\u7C7B\u9020\u6210\u5F71\u54CD\uFF0C\u4EA7\u751F\u66F4\u591A\u7684\u9519\u8BEF\u3002\u8FD9\u662F\u600E\u4E48\u529E\u5462\uFF1F\u6211\u4EEC\u53EF\u4EE5\u4E3A\u8FD9\u4E2A\u7279\u4F8B(Son2)\u521B\u5EFA\u4E00\u4E2A\u65B0\u7684\u7236\u7C7B(Father2)\uFF0C\u8FD9\u4E2A\u65B0\u7684\u7236\u7C7B\u62E5\u6709\u539F\u7236\u7C7B\u7684\u90E8\u5206\u529F\u80FD(Father2\u5E76\u4E0D\u7EE7\u627FFather,\u800C\u662F\u6301\u6709Father\u7684\u4E00\u4E2A\u5F15\u7528\uFF0C\u7EC4\u5408Father,\u8C03\u7528Father\u91CC\u7684\u529F\u80FD)\uFF0C\u53C8\u6709\u4E0D\u540C\u7684\u529F\u80FD\u3002\u8FD9\u6837\u65E2\u6EE1\u8DB3\u4E86\u91CC\u6C0F\u66FF\u6362\u539F\u5219\uFF0C\u53C8\u6EE1\u8DB3\u4E86\u8FD9\u4E2A\u7279\u4F8B\u7684\u9700\u6C42\u3002</p><h4 id="_2-\u5B50\u7C7B\u4E2D\u53EF\u4EE5\u589E\u52A0\u81EA\u5DF1\u7279\u6709\u7684\u65B9\u6CD5" tabindex="-1"><a class="header-anchor" href="#_2-\u5B50\u7C7B\u4E2D\u53EF\u4EE5\u589E\u52A0\u81EA\u5DF1\u7279\u6709\u7684\u65B9\u6CD5" aria-hidden="true">#</a> 2. \u5B50\u7C7B\u4E2D\u53EF\u4EE5\u589E\u52A0\u81EA\u5DF1\u7279\u6709\u7684\u65B9\u6CD5</h4><p>\u8FD9\u4E2A\u5F88\u5BB9\u6613\u7406\u89E3\uFF0C\u5B50\u7C7B\u7EE7\u627F\u4E86\u7236\u7C7B\uFF0C\u62E5\u6709\u4E86\u7236\u7C7B\u548C\u65B9\u6CD5\uFF0C\u540C\u65F6\u8FD8\u53EF\u4EE5\u5B9A\u4E49\u81EA\u5DF1\u6709\uFF0C\u800C\u7236\u7C7B\u6CA1\u6709\u7684\u65B9\u6CD5\u3002\u8FD9\u662F\u5728\u7EE7\u627F\u7236\u7C7B\u65B9\u6CD5\u7684\u57FA\u7840\u4E0A\u8FDB\u884C\u529F\u80FD\u7684\u6269\u5C55\uFF0C\u7B26\u5408\u91CC\u6C0F\u66FF\u6362\u539F\u5219\u3002</p><h4 id="_3-\u5F53\u5B50\u7C7B\u8986\u76D6\u6216\u5B9E\u73B0\u7236\u7C7B\u7684\u65B9\u6CD5\u65F6-\u65B9\u6CD5\u7684\u524D\u7F6E\u6761\u4EF6-\u5373\u65B9\u6CD5\u7684\u5F62\u53C2-\u8981\u6BD4\u7236\u7C7B\u65B9\u6CD5\u7684\u8F93\u5165\u53C2\u6570\u66F4\u5BBD\u677E" tabindex="-1"><a class="header-anchor" href="#_3-\u5F53\u5B50\u7C7B\u8986\u76D6\u6216\u5B9E\u73B0\u7236\u7C7B\u7684\u65B9\u6CD5\u65F6-\u65B9\u6CD5\u7684\u524D\u7F6E\u6761\u4EF6-\u5373\u65B9\u6CD5\u7684\u5F62\u53C2-\u8981\u6BD4\u7236\u7C7B\u65B9\u6CD5\u7684\u8F93\u5165\u53C2\u6570\u66F4\u5BBD\u677E" aria-hidden="true">#</a> 3. \u5F53\u5B50\u7C7B\u8986\u76D6\u6216\u5B9E\u73B0\u7236\u7C7B\u7684\u65B9\u6CD5\u65F6\uFF0C\u65B9\u6CD5\u7684\u524D\u7F6E\u6761\u4EF6\uFF08\u5373\u65B9\u6CD5\u7684\u5F62\u53C2\uFF09\u8981\u6BD4\u7236\u7C7B\u65B9\u6CD5\u7684\u8F93\u5165\u53C2\u6570\u66F4\u5BBD\u677E</h4><h4 id="_4-\u5F53\u5B50\u7C7B\u7684\u65B9\u6CD5\u5B9E\u73B0\u7236\u7C7B\u7684-\u62BD\u8C61-\u65B9\u6CD5\u65F6-\u65B9\u6CD5\u7684\u540E\u7F6E\u6761\u4EF6-\u5373\u65B9\u6CD5\u7684\u8FD4\u56DE\u503C-\u8981\u6BD4\u7236\u7C7B\u66F4\u4E25\u683C" tabindex="-1"><a class="header-anchor" href="#_4-\u5F53\u5B50\u7C7B\u7684\u65B9\u6CD5\u5B9E\u73B0\u7236\u7C7B\u7684-\u62BD\u8C61-\u65B9\u6CD5\u65F6-\u65B9\u6CD5\u7684\u540E\u7F6E\u6761\u4EF6-\u5373\u65B9\u6CD5\u7684\u8FD4\u56DE\u503C-\u8981\u6BD4\u7236\u7C7B\u66F4\u4E25\u683C" aria-hidden="true">#</a> 4. \u5F53\u5B50\u7C7B\u7684\u65B9\u6CD5\u5B9E\u73B0\u7236\u7C7B\u7684\uFF08\u62BD\u8C61\uFF09\u65B9\u6CD5\u65F6\uFF0C\u65B9\u6CD5\u7684\u540E\u7F6E\u6761\u4EF6\uFF08\u5373\u65B9\u6CD5\u7684\u8FD4\u56DE\u503C\uFF09\u8981\u6BD4\u7236\u7C7B\u66F4\u4E25\u683C</h4><h3 id="\u63A5\u53E3\u9694\u79BB\u539F\u5219" tabindex="-1"><a class="header-anchor" href="#\u63A5\u53E3\u9694\u79BB\u539F\u5219" aria-hidden="true">#</a> \u63A5\u53E3\u9694\u79BB\u539F\u5219</h3><p>\u63A5\u53E3\u9694\u79BB\u539F\u5219\uFF08Interface Segregation Principle\uFF09\uFF1A\u5BA2\u6237\u7AEF\u4E0D\u5E94\u88AB\u5F3A\u8FEB\u4F9D\u8D56\u4E8E\u5176\u4E0D\u9700\u8981\u7684\u65B9\u6CD5\u3002\u8981\u4E3A\u5404\u4E2A\u7C7B\u5EFA\u7ACB\u5B83\u4EEC\u9700\u8981\u7684\u4E13\u7528\u63A5\u53E3\uFF0C\u800C\u4E0D\u8981\u8BD5\u56FE\u53BB\u5EFA\u7ACB\u4E00\u4E2A\u5F88\u5E9E\u5927\u7684\u63A5\u53E3\u4F9B\u6240\u6709\u4F9D\u8D56\u5B83\u7684\u7C7B\u53BB\u8C03\u7528\u3002</p><p>\u63A5\u53E3\u9694\u79BB\u539F\u5219\u548C\u5355\u4E00\u804C\u8D23\u90FD\u662F\u4E3A\u4E86\u63D0\u9AD8\u7C7B\u7684\u5185\u805A\u6027\u3001\u964D\u4F4E\u5B83\u4EEC\u4E4B\u95F4\u7684\u8026\u5408\u6027\uFF0C\u4F53\u73B0\u4E86\u5C01\u88C5\u7684\u601D\u60F3\uFF0C\u4F46\u4E24\u8005\u662F\u4E0D\u540C\u7684\uFF1A</p><ul><li>\u5355\u4E00\u804C\u8D23\u539F\u5219\u6CE8\u91CD\u7684\u662F\u804C\u8D23\uFF0C\u800C\u63A5\u53E3\u9694\u79BB\u539F\u5219\u6CE8\u91CD\u7684\u662F\u5BF9\u63A5\u53E3\u4F9D\u8D56\u7684\u9694\u79BB\u3002</li><li>\u5355\u4E00\u804C\u8D23\u539F\u5219\u4E3B\u8981\u662F\u7EA6\u675F\u7C7B\uFF0C\u5B83\u9488\u5BF9\u7684\u662F\u7A0B\u5E8F\u4E2D\u7684\u5B9E\u73B0\u548C\u7EC6\u8282\uFF1B\u63A5\u53E3\u9694\u79BB\u539F\u5219\u4E3B\u8981\u7EA6\u675F\u63A5\u53E3\uFF0C\u4E3B\u8981\u9488\u5BF9\u62BD\u8C61\u548C\u7A0B\u5E8F\u6574\u4F53\u6846\u67B6\u7684\u6784\u5EFA\u3002</li></ul><h3 id="\u4F9D\u8D56\u5012\u7F6E\u539F\u5219" tabindex="-1"><a class="header-anchor" href="#\u4F9D\u8D56\u5012\u7F6E\u539F\u5219" aria-hidden="true">#</a> \u4F9D\u8D56\u5012\u7F6E\u539F\u5219</h3><p>\u4F9D\u8D56\u5012\u7F6E\u539F\u5219\uFF08Dependency Inversion Principle\uFF09\uFF1A\u9AD8\u5C42\u6B21\u7684\u7C7B\u4E0D\u5E94\u8BE5\u4F9D\u8D56\u4E8E\u4F4E\u5C42\u6B21\u7684\u7C7B\uFF0C\u4E24\u8005\u90FD\u5E94\u8BE5\u4F9D\u8D56\u4E8E\u62BD\u8C61\u63A5\u53E3\u3002\u62BD\u8C61\u63A5\u53E3\u4E0D\u5E94\u4F9D\u8D56\u4E8E\u5177\u4F53\u5B9E\u73B0\uFF0C\u5177\u4F53\u5B9E\u73B0\u5E94\u8BE5\u4F9D\u8D56\u4E8E\u62BD\u8C61\u63A5\u53E3\u3002</p>',14);function b(m,S){const n=h("ExternalLinkIcon");return t(),d(s,null,[p,a("p",null,[l,a("a",_,[f,o(n)]),u]),x],64)}var I=i(c,[["render",b],["__file","index.html.vue"]]);export{I as default};
